sql:
SELECT DATE(scheduled_time) AS activity_date, COUNT(*) AS activities_count 
FROM activities 
GROUP BY activity_date;

SELECT condition_id, AVG(humidity) AS average_humidity, AVG(wind_speed) AS average_wind_speed
FROM weather_conditions
GROUP BY condition_id;

SELECT wind_speed, humidity 
FROM weather_conditions 
WHERE cloud_cover <> 'overcast';

SELECT U.first_name || ' ' || U.last_name AS full_name, P.play AS play_decision
FROM play_decisions P
JOIN users U ON P.decision_by = U.user_id;

SELECT COUNT(*) 
FROM play_decisions 
WHERE play = 'no' AND reason LIKE '%Safety%';

external_knowledge:
- 'rainy' weather leads to the decision to not play ('NO');
- Any weather other than 'rainy' leads to the decision to play ('YES');
- The term 'individuals' refers to user entries in the database;
- The decision to play or not is based on weather outlooks recorded in the database.

sql:
SELECT outlook, temperature, humidity, AVG(humidity) as average_humidity
FROM weather_conditions
GROUP BY outlook, temperature, humidity;

SELECT feedback.feedback_text, users.username 
FROM feedback
INNER JOIN users ON feedback.user_id = users.user_id;

SELECT outlook, temperature, humidity
FROM weather_conditions
WHERE condition_id = 1;
